// CSD_RATIONALE_BEGIN
// This strategy uses a modified Crane-style approach to handle tasks with both plain text and a delimited constrained part.
// It first generates unconstrained steps until it reaches the constrained segment, where it switches to constrained steps.
// The loop continues until either the maximum number of steps is reached or the prefix is complete. If the task uses delimiters,
// it handles the plain text and constrained segments separately using if/else.
// The strategy also includes RollbackToValidPrefix to repair the prefix if necessary.
// CSD_RATIONALE_END

generated := [];

var stepCounter := 0;
var hasValid := false;
var validTokens := parser.ValidNextTokens(prompt);

while stepsLeft > 0 && !parser.IsCompletePrefix(generated)
  invariant lm.ValidTokensIdsLogits()
  invariant parser.IsValidPrefix(generated)
  invariant 0 <= stepsLeft <= maxSteps
  invariant |generated| + stepsLeft == maxSteps
  decreases stepsLeft
{
  // Increment step counter
  stepCounter := stepCounter + 1;

  // Check if we are still in the unconstrained part
  if parser.IsCompletePrefix(generated) || |generated| == 0
  {
    // Generate one unconstrained step
    var next, newSteps := helpers.UnconstrainedStep(lm, prompt, generated, stepsLeft);
    generated := generated + [next];
    stepsLeft := newSteps;

    // Check if the generated token is valid and not a delimiter
    hasValid := exists token :: token in validTokens && parser.ValidNextToken(generated, token);
  }
  else
  {
    // Generate one constrained step
    var next, newSteps := helpers.ConstrainedStep(lm, parser, prompt, generated, stepsLeft);
    generated := generated + [next];
    stepsLeft := newSteps;

    // Check if the generated token is valid and not a delimiter
    hasValid := exists token :: token in validTokens && parser.ValidNextToken(generated, token);
  }

  // If no valid token was generated in this step, rollback to the last valid prefix
  if !hasValid
  {
    generated := helpers.RollbackToValidPrefix(parser, generated);
    hasValid := true;
  }

  // Check if the prefix is complete and not dead
  if parser.IsCompletePrefix(generated) && !parser.IsDeadPrefix(generated)
  {
    break;
  }
}

